classdef Spin2Matcher < handle
    %SPIN2MATCHER Polarity-invariant gradient matching for uint8 images.
    %
    % Source-image coordinates are related to reference coordinates by
    %
    %   sourceXY = referenceXY + [DisplacementX, DisplacementY].
    %
    % Pixel coordinates are one-based [x, y] = [column, row]. Matching is
    % performed on normalized squared complex gradients. The descriptor is
    % not invertible because gradient polarity and absolute intensity are
    % discarded.

    properties (SetAccess = private)
        ReferenceImage (:, :) uint8
        SourceImage (:, :) uint8
        ReferenceSpin2 (:, :) single = zeros(0, 0, "single")
        SourceSpin2 (:, :) single = zeros(0, 0, "single")
        ReferenceConfidence (:, :) single = zeros(0, 0, "single")
        SourceConfidence (:, :) single = zeros(0, 0, "single")
        IsPrepared (1, 1) logical = false
    end

    methods
        function obj = Spin2Matcher(referenceImage, sourceImage)
            arguments
                referenceImage (:, :) ...
                    {mustBeA(referenceImage, "uint8"), mustBeNonempty}
                sourceImage (:, :) ...
                    {mustBeA(sourceImage, "uint8"), mustBeNonempty, ...
                    mustHaveSameSize(sourceImage, referenceImage)}
            end

            obj.ReferenceImage = referenceImage;
            obj.SourceImage = sourceImage;
        end

        function features = prepareComplexGradients(obj, options)
            %PREPARECOMPLEXGRADIENTS Compute and cache spin-2 descriptors.
            %
            % SmoothingSigma is measured in pixels. GradientThreshold is
            % measured in uint8 intensity levels per pixel and controls the
            % soft confidence ramp; it is not a hard edge threshold.

            arguments
                obj (1, 1) Spin2Matcher
                options.SmoothingSigma (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0.8
                options.GradientThreshold (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 4
            end

            [obj.ReferenceSpin2, obj.ReferenceConfidence] = ...
                Spin2Matcher.prepareImage(obj.ReferenceImage, ...
                options.SmoothingSigma, options.GradientThreshold);
            [obj.SourceSpin2, obj.SourceConfidence] = ...
                Spin2Matcher.prepareImage(obj.SourceImage, ...
                options.SmoothingSigma, options.GradientThreshold);
            obj.IsPrepared = true;

            features = struct( ...
                "Reference", obj.ReferenceSpin2, ...
                "Source", obj.SourceSpin2, ...
                "ReferenceConfidence", obj.ReferenceConfidence, ...
                "SourceConfidence", obj.SourceConfidence);
        end

        function result = match(obj, searchOffsets, options)
            %MATCH Match one resolution level using parallel 2-D tiles.
            %
            % searchOffsets is K-by-2 [dx, dy] in integer working-image
            % pixels. TileSize and TileOverlap are [height, width]. The
            % requested overlap is a minimum; the matcher always expands
            % the data halo enough to cover the patch and supplied offsets.

            arguments
                obj (1, 1) Spin2Matcher
                searchOffsets (:, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonempty}
                options.PatchRadius (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 4
                options.Stride (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 1
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = [512, 512]
                options.TileOverlap (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = [0, 0]
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.05
                options.ConstrainMatchesToTile (1, 1) logical = false
                options.NumWorkers (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
            end

            if ~obj.IsPrepared
                error("Spin2Matcher:NotPrepared", ...
                    "Call prepareComplexGradients before match.");
            end

            pool = Spin2Matcher.ensureThreadPool;
            numberOfWorkers = Spin2Matcher.resolveWorkerCount( ...
                pool, options.NumWorkers);
            imageSize = size(obj.ReferenceImage);
            [sampleRows, sampleColumns] = Spin2Matcher.sampleGrid( ...
                imageSize, options.PatchRadius, options.Stride);
            tiles = Spin2Matcher.makeTiles( ...
                imageSize, sampleRows, sampleColumns, options.TileSize);
            offsetsByTile = repmat({searchOffsets}, numel(tiles), 1);

            [result, statistics] = Spin2Matcher.runTiledLevel( ...
                obj.ReferenceSpin2, obj.SourceSpin2, ...
                obj.ReferenceConfidence, obj.SourceConfidence, ...
                imageSize, sampleRows, sampleColumns, tiles, ...
                offsetsByTile, options.PatchRadius, ...
                options.TileOverlap, options.MinimumSupportFraction, ...
                options.ConstrainMatchesToTile, numberOfWorkers);
            result.SearchOffsets = searchOffsets;
            result.Statistics = statistics;
        end

        function result = matchPyramid(obj, overviewSearchOffsets, options)
            %MATCHPYRAMID Run overview matching and tiled refinement.
            %
            % overviewSearchOffsets is expressed in overview-level pixels.
            % By default, one overview pass is followed directly by a
            % full-resolution pass. UseIntermediateLevels inserts every
            % PyramidDecimation level between overview and full resolution.

            arguments
                obj (1, 1) Spin2Matcher
                overviewSearchOffsets (:, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonempty}
                options.OverviewMaximumDimension (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 1024
                options.PyramidDecimation (1, 1) double ...
                    {mustBeFinite, mustBeInteger, ...
                    mustBeGreaterThanOrEqual( ...
                    options.PyramidDecimation, 2)} = 2
                options.UseIntermediateLevels (1, 1) logical = false
                options.PyramidFactors (1, :) double ...
                    {mustBePyramidFactors} = zeros(1, 0)
                options.ResidualSearchRadius (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = [4, 4]
                options.PatchRadius (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 5
                options.Stride (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = [512, 512]
                options.TileOverlap (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = [0, 0]
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.05
                options.ConstrainMatchesToTile (1, 1) logical = false
                options.SmoothingSigma (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0.8
                options.GradientThreshold (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 4
                options.NumWorkers (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
            end

            pool = Spin2Matcher.ensureThreadPool;
            numberOfWorkers = Spin2Matcher.resolveWorkerCount( ...
                pool, options.NumWorkers);
            factors = Spin2Matcher.selectPyramidFactors( ...
                size(obj.ReferenceImage), options.OverviewMaximumDimension, ...
                options.PyramidDecimation, options.UseIntermediateLevels, ...
                options.PyramidFactors);

            previousResult = [];
            previousFactor = [];
            levelReports = cell(numel(factors), 1);
            for levelIndex = 1:numel(factors)
                factor = factors(levelIndex);
                referenceImage = Spin2Matcher.downsampleImage( ...
                    obj.ReferenceImage, factor);
                sourceImage = Spin2Matcher.downsampleImage( ...
                    obj.SourceImage, factor);

                prepareTimer = tic;
                [referenceSpin2, referenceConfidence] = ...
                    Spin2Matcher.prepareImage(referenceImage, ...
                    options.SmoothingSigma, options.GradientThreshold);
                [sourceSpin2, sourceConfidence] = ...
                    Spin2Matcher.prepareImage(sourceImage, ...
                    options.SmoothingSigma, options.GradientThreshold);
                prepareSeconds = toc(prepareTimer);

                imageSize = size(referenceImage);
                [sampleRows, sampleColumns] = Spin2Matcher.sampleGrid( ...
                    imageSize, options.PatchRadius, options.Stride);
                tiles = Spin2Matcher.makeTiles( ...
                    imageSize, sampleRows, sampleColumns, options.TileSize);

                if levelIndex == 1
                    offsetsByTile = repmat( ...
                        {overviewSearchOffsets}, numel(tiles), 1);
                else
                    [predictedDx, predictedDy] = ...
                        Spin2Matcher.interpolatePrediction( ...
                        previousResult, previousFactor, factor, ...
                        sampleRows, sampleColumns);
                    offsetsByTile = Spin2Matcher.tileLocalOffsets( ...
                        tiles, predictedDx, predictedDy, ...
                        options.ResidualSearchRadius, imageSize);
                end

                matchTimer = tic;
                [levelResult, levelStatistics] = ...
                    Spin2Matcher.runTiledLevel( ...
                    referenceSpin2, sourceSpin2, ...
                    referenceConfidence, sourceConfidence, imageSize, ...
                    sampleRows, sampleColumns, tiles, offsetsByTile, ...
                    options.PatchRadius, options.TileOverlap, ...
                    options.MinimumSupportFraction, ...
                    options.ConstrainMatchesToTile, numberOfWorkers);
                matchSeconds = toc(matchTimer);
                levelResult.PyramidFactor = factor;

                candidateCounts = levelStatistics.TileCandidateCounts;
                levelReports{levelIndex} = struct( ...
                    "Factor", factor, ...
                    "ImageSize", imageSize, ...
                    "TileCount", levelStatistics.TileCount, ...
                    "CandidateCountMinimum", min(candidateCounts), ...
                    "CandidateCountMedian", median(candidateCounts), ...
                    "CandidateCountMaximum", max(candidateCounts), ...
                    "PrepareSeconds", prepareSeconds, ...
                    "MatchSeconds", matchSeconds, ...
                    "NumWorkers", numberOfWorkers, ...
                    "TileOverlap", levelStatistics.TileOverlapActual);
                previousResult = levelResult;
                previousFactor = factor;
            end

            result = previousResult;
            result.PyramidFactors = factors;
            result.LevelReports = vertcat(levelReports{:});
            result.OverviewSearchOffsets = overviewSearchOffsets;
        end

        function tuning = tuneThreads(obj, searchOffsets, options)
            %TUNETHREADS Benchmark tile matching across thread counts.

            arguments
                obj (1, 1) Spin2Matcher
                searchOffsets (:, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonempty}
                options.WorkerCounts (1, :) double ...
                    {mustBeInteger, mustBePositive} = zeros(1, 0)
                options.Exhaustive (1, 1) logical = false
                options.Repetitions (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 2
                options.PatchRadius (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 4
                options.Stride (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 4
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = [512, 512]
                options.TileOverlap (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = [0, 0]
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.05
                options.ConstrainMatchesToTile (1, 1) logical = false
            end

            if ~obj.IsPrepared
                error("Spin2Matcher:NotPrepared", ...
                    "Call prepareComplexGradients before tuneThreads.");
            end

            pool = Spin2Matcher.ensureThreadPool;
            maximumWorkers = pool.NumWorkers;
            if isempty(options.WorkerCounts)
                if options.Exhaustive
                    workerCounts = 1:maximumWorkers;
                else
                    powers = 2 .^ (0:floor(log2(maximumWorkers)));
                    workerCounts = unique([powers, maximumWorkers]);
                end
            else
                workerCounts = unique(options.WorkerCounts);
            end
            if any(workerCounts > maximumWorkers)
                error("Spin2Matcher:TooManyWorkers", ...
                    "WorkerCounts cannot exceed the thread pool size of %d.", ...
                    maximumWorkers);
            end

            obj.match(searchOffsets, ...
                PatchRadius=options.PatchRadius, Stride=options.Stride, ...
                TileSize=options.TileSize, TileOverlap=options.TileOverlap, ...
                MinimumSupportFraction=options.MinimumSupportFraction, ...
                ConstrainMatchesToTile=options.ConstrainMatchesToTile, ...
                NumWorkers=workerCounts(1));

            elapsedSeconds = zeros(numel(workerCounts), options.Repetitions);
            referenceResult = [];
            tileCount = 0;
            for workerIndex = 1:numel(workerCounts)
                for repetition = 1:options.Repetitions
                    timer = tic;
                    candidateResult = obj.match(searchOffsets, ...
                        PatchRadius=options.PatchRadius, ...
                        Stride=options.Stride, ...
                        TileSize=options.TileSize, ...
                        TileOverlap=options.TileOverlap, ...
                        MinimumSupportFraction= ...
                        options.MinimumSupportFraction, ...
                        ConstrainMatchesToTile= ...
                        options.ConstrainMatchesToTile, ...
                        NumWorkers=workerCounts(workerIndex));
                    elapsedSeconds(workerIndex, repetition) = toc(timer);
                    tileCount = candidateResult.Statistics.TileCount;
                    if isempty(referenceResult)
                        referenceResult = candidateResult;
                    elseif ~Spin2Matcher.resultsEquivalent( ...
                            referenceResult, candidateResult)
                        error("Spin2Matcher:TuningMismatch", ...
                            "Thread-count benchmark results are not equivalent.");
                    end
                end
            end

            medianSeconds = median(elapsedSeconds, 2);
            speedup = medianSeconds(1) ./ medianSeconds;
            tilesPerSecond = tileCount ./ medianSeconds;
            [~, fastestIndex] = min(medianSeconds);
            benchmarkTable = table(workerCounts(:), medianSeconds, ...
                speedup, tilesPerSecond, ...
                VariableNames=["Workers", "MedianSeconds", ...
                "Speedup", "TilesPerSecond"]);
            tuning = struct( ...
                "Results", benchmarkTable, ...
                "RecommendedWorkers", workerCounts(fastestIndex), ...
                "PoolWorkers", maximumWorkers, ...
                "Repetitions", options.Repetitions, ...
                "TileCount", tileCount);
        end
    end

    methods (Static, Access = private)
        function [descriptor, confidence] = prepareImage( ...
                image, smoothingSigma, gradientThreshold)
            intensity = single(image);
            smoothingRadius = 0;

            if smoothingSigma > 0
                smoothingRadius = ceil(3 * smoothingSigma);
                coordinates = single(-smoothingRadius:smoothingRadius);
                kernel = exp(-(coordinates .^ 2) ...
                    ./ single(2 * smoothingSigma ^ 2));
                kernel = kernel ./ sum(kernel);
                intensity = conv2(kernel(:), kernel(:).', ...
                    intensity, "same");
            end

            [imageHeight, imageWidth] = size(intensity);
            gradientX = zeros(imageHeight, imageWidth, "single");
            gradientY = zeros(imageHeight, imageWidth, "single");

            if imageWidth > 1
                gradientX(:, 2:end-1) = single(0.5) .* ( ...
                    intensity(:, 3:end) - intensity(:, 1:end-2));
                gradientX(:, 1) = intensity(:, 2) - intensity(:, 1);
                gradientX(:, end) = intensity(:, end) ...
                    - intensity(:, end-1);
            end
            if imageHeight > 1
                gradientY(2:end-1, :) = single(0.5) .* ( ...
                    intensity(3:end, :) - intensity(1:end-2, :));
                gradientY(1, :) = intensity(2, :) - intensity(1, :);
                gradientY(end, :) = intensity(end, :) ...
                    - intensity(end-1, :);
            end

            magnitudeSquared = gradientX .* gradientX ...
                + gradientY .* gradientY;
            magnitude = sqrt(magnitudeSquared);
            descriptor = complex( ...
                gradientX .* gradientX - gradientY .* gradientY, ...
                single(2) .* gradientX .* gradientY) ...
                ./ max(magnitudeSquared, eps("single"));
            confidence = min(magnitude ...
                ./ single(gradientThreshold), single(1));
            descriptor(magnitudeSquared == 0) = 0;

            invalidBorder = smoothingRadius + 1;
            if smoothingRadius > 0
                confidence(1:min(invalidBorder, imageHeight), :) = 0;
                confidence(max(1, imageHeight-invalidBorder+1):end, :) = 0;
                confidence(:, 1:min(invalidBorder, imageWidth)) = 0;
                confidence(:, max(1, imageWidth-invalidBorder+1):end) = 0;
                descriptor(confidence == 0) = 0;
            end
        end

        function [sampleRows, sampleColumns] = sampleGrid( ...
                imageSize, patchRadius, stride)
            sampleRows = (1 + patchRadius):stride: ...
                (imageSize(1) - patchRadius);
            sampleColumns = (1 + patchRadius):stride: ...
                (imageSize(2) - patchRadius);
        end

        function tiles = makeTiles( ...
                imageSize, sampleRows, sampleColumns, tileSize)
            rowStarts = 1:tileSize(1):imageSize(1);
            columnStarts = 1:tileSize(2):imageSize(2);
            tiles = cell(numel(rowStarts) * numel(columnStarts), 1);
            tileIndex = 0;
            for rowStart = rowStarts
                rowEnd = min(rowStart + tileSize(1) - 1, imageSize(1));
                rowIndices = find(sampleRows >= rowStart ...
                    & sampleRows <= rowEnd);
                for columnStart = columnStarts
                    columnEnd = min(columnStart + tileSize(2) - 1, ...
                        imageSize(2));
                    columnIndices = find(sampleColumns >= columnStart ...
                        & sampleColumns <= columnEnd);
                    if ~isempty(rowIndices) && ~isempty(columnIndices)
                        tileIndex = tileIndex + 1;
                        tiles{tileIndex} = struct( ...
                            "CoreBounds", ...
                            [rowStart, rowEnd, columnStart, columnEnd], ...
                            "RowIndices", rowIndices, ...
                            "ColumnIndices", columnIndices);
                    end
                end
            end
            tiles = tiles(1:tileIndex);
        end

        function [result, statistics] = runTiledLevel( ...
                referenceSpin2, sourceSpin2, ...
                referenceConfidence, sourceConfidence, imageSize, ...
                sampleRows, sampleColumns, tiles, offsetsByTile, ...
                patchRadius, requestedOverlap, minimumSupportFraction, ...
                constrainMatchesToTile, numberOfWorkers)
            numberOfTiles = numel(tiles);
            tileResults = cell(numberOfTiles, 1);
            parfor (tileIndex = 1:numberOfTiles, numberOfWorkers)
                tileResults{tileIndex} = Spin2Matcher.computeTile( ...
                    referenceSpin2, sourceSpin2, ...
                    referenceConfidence, sourceConfidence, imageSize, ...
                    sampleRows, sampleColumns, tiles{tileIndex}, ...
                    offsetsByTile{tileIndex}, patchRadius, ...
                    requestedOverlap, minimumSupportFraction, ...
                    constrainMatchesToTile);
            end

            outputSize = [numel(sampleRows), numel(sampleColumns)];
            bestCost = nan(outputSize, "single");
            margin = nan(outputSize, "single");
            bestDx = nan(outputSize, "single");
            bestDy = nan(outputSize, "single");
            valid = false(outputSize);
            halos = zeros(numberOfTiles, 4);
            coreBounds = zeros(numberOfTiles, 4);
            candidateCounts = zeros(numberOfTiles, 1);
            for tileIndex = 1:numberOfTiles
                tile = tiles{tileIndex};
                tileResult = tileResults{tileIndex};
                rowIndices = tile.RowIndices;
                columnIndices = tile.ColumnIndices;
                bestCost(rowIndices, columnIndices) = tileResult.Cost;
                margin(rowIndices, columnIndices) = tileResult.Margin;
                bestDx(rowIndices, columnIndices) = ...
                    tileResult.DisplacementX;
                bestDy(rowIndices, columnIndices) = ...
                    tileResult.DisplacementY;
                valid(rowIndices, columnIndices) = tileResult.Valid;
                halos(tileIndex, :) = tileResult.Halo;
                coreBounds(tileIndex, :) = tile.CoreBounds;
                candidateCounts(tileIndex) = tileResult.CandidateCount;
            end

            if isempty(halos)
                actualOverlap = [0, 0];
            else
                actualOverlap = [max(halos(:, 1) + halos(:, 2)), ...
                    max(halos(:, 3) + halos(:, 4))];
            end
            statistics = struct( ...
                "TileCount", numberOfTiles, ...
                "TileCoreBounds", coreBounds, ...
                "TileHalos", halos, ...
                "TileOverlapRequested", requestedOverlap, ...
                "TileOverlapActual", actualOverlap, ...
                "TileCandidateCounts", candidateCounts, ...
                "NumWorkers", numberOfWorkers);
            result = struct( ...
                "ReferenceX", sampleColumns, ...
                "ReferenceY", sampleRows(:), ...
                "DisplacementX", bestDx, ...
                "DisplacementY", bestDy, ...
                "Cost", bestCost, ...
                "Margin", margin, ...
                "Valid", valid);
        end

        function result = computeTile( ...
                referenceSpin2, sourceSpin2, ...
                referenceConfidenceImage, sourceConfidenceImage, ...
                imageSize, sampleRows, sampleColumns, tile, ...
                searchOffsets, patchRadius, requestedOverlap, ...
                minimumSupportFraction, constrainMatchesToTile)
            rowIndices = tile.RowIndices;
            columnIndices = tile.ColumnIndices;
            tileCenterRows = sampleRows(rowIndices);
            tileCenterColumns = sampleColumns(columnIndices);
            coreBounds = tile.CoreBounds;

            extendedRowStart = tileCenterRows(1) - patchRadius;
            extendedRowEnd = tileCenterRows(end) + patchRadius;
            extendedColumnStart = tileCenterColumns(1) - patchRadius;
            extendedColumnEnd = tileCenterColumns(end) + patchRadius;
            extendedRows = extendedRowStart:extendedRowEnd;
            extendedColumns = extendedColumnStart:extendedColumnEnd;
            referenceFeature = referenceSpin2(extendedRows, extendedColumns);
            referenceConfidence = referenceConfidenceImage( ...
                extendedRows, extendedColumns);

            rowPick = tileCenterRows - patchRadius ...
                - extendedRowStart + 1;
            columnPick = tileCenterColumns - patchRadius ...
                - extendedColumnStart + 1;
            outputSize = [numel(tileCenterRows), ...
                numel(tileCenterColumns)];
            bestCost = inf(outputSize, "single");
            secondCost = inf(outputSize, "single");
            bestDx = nan(outputSize, "single");
            bestDy = nan(outputSize, "single");

            patchWidth = 2 * patchRadius + 1;
            patchArea = patchWidth * patchWidth;
            boxKernel = ones(patchWidth, patchWidth, "single");
            minimumSupport = single(minimumSupportFraction * patchArea);

            for offsetIndex = 1:size(searchOffsets, 1)
                dx = searchOffsets(offsetIndex, 1);
                dy = searchOffsets(offsetIndex, 2);
                sourceRows = extendedRows + dy;
                sourceColumns = extendedColumns + dx;
                validSourceRows = sourceRows >= 1 ...
                    & sourceRows <= imageSize(1);
                validSourceColumns = sourceColumns >= 1 ...
                    & sourceColumns <= imageSize(2);

                sourceFeature = zeros(size(referenceFeature), ...
                    "like", referenceFeature);
                sourceConfidence = zeros(size(referenceConfidence), ...
                    "single");
                sourceFeature(validSourceRows, validSourceColumns) = ...
                    sourceSpin2(sourceRows(validSourceRows), ...
                    sourceColumns(validSourceColumns));
                sourceConfidence(validSourceRows, validSourceColumns) = ...
                    sourceConfidenceImage(sourceRows(validSourceRows), ...
                    sourceColumns(validSourceColumns));

                pixelWeight = min(referenceConfidence, sourceConfidence);
                orientationCost = single(0.5) .* (1 - real( ...
                    referenceFeature .* conj(sourceFeature)));
                orientationCost = max(single(0), ...
                    min(single(1), orientationCost));
                support = conv2(pixelWeight, boxKernel, "valid");
                costSum = conv2(pixelWeight .* orientationCost, ...
                    boxKernel, "valid");
                candidateSupport = support(rowPick, columnPick);
                candidateCost = costSum(rowPick, columnPick) ...
                    ./ candidateSupport;

                rowsInBounds = tileCenterRows + dy >= 1 + patchRadius ...
                    & tileCenterRows + dy <= imageSize(1) - patchRadius;
                columnsInBounds = tileCenterColumns + dx >= ...
                    1 + patchRadius ...
                    & tileCenterColumns + dx <= ...
                    imageSize(2) - patchRadius;
                candidateValid = rowsInBounds(:) ...
                    & columnsInBounds(:).';
                if constrainMatchesToTile
                    rowsInTile = tileCenterRows + dy >= coreBounds(1) ...
                        & tileCenterRows + dy <= coreBounds(2);
                    columnsInTile = tileCenterColumns + dx >= coreBounds(3) ...
                        & tileCenterColumns + dx <= coreBounds(4);
                    candidateValid = candidateValid ...
                        & rowsInTile(:) & columnsInTile(:).';
                end
                candidateValid = candidateValid ...
                    & candidateSupport >= minimumSupport;
                candidateCost(~candidateValid) = inf("single");

                isBetter = candidateCost < bestCost;
                secondCost(isBetter) = bestCost(isBetter);
                bestCost(isBetter) = candidateCost(isBetter);
                bestDx(isBetter) = single(dx);
                bestDy(isBetter) = single(dy);
                isSecond = ~isBetter & candidateCost < secondCost;
                secondCost(isSecond) = candidateCost(isSecond);
            end

            valid = isfinite(bestCost);
            margin = secondCost - bestCost;
            margin(~valid | ~isfinite(secondCost)) = nan("single");
            bestCost(~valid) = nan("single");

            minimumDy = min(searchOffsets(:, 2));
            maximumDy = max(searchOffsets(:, 2));
            minimumDx = min(searchOffsets(:, 1));
            maximumDx = max(searchOffsets(:, 1));
            requestedTop = floor(requestedOverlap(1) / 2);
            requestedBottom = ceil(requestedOverlap(1) / 2);
            requestedLeft = floor(requestedOverlap(2) / 2);
            requestedRight = ceil(requestedOverlap(2) / 2);
            halo = [ ...
                max(patchRadius + max(0, -minimumDy), requestedTop), ...
                max(patchRadius + max(0, maximumDy), requestedBottom), ...
                max(patchRadius + max(0, -minimumDx), requestedLeft), ...
                max(patchRadius + max(0, maximumDx), requestedRight)];
            result = struct( ...
                "DisplacementX", bestDx, ...
                "DisplacementY", bestDy, ...
                "Cost", bestCost, ...
                "Margin", margin, ...
                "Valid", valid, ...
                "Halo", halo, ...
                "CandidateCount", size(searchOffsets, 1));
        end

        function factors = selectPyramidFactors( ...
                imageSize, overviewMaximumDimension, decimation, ...
                useIntermediateLevels, explicitFactors)
            if ~isempty(explicitFactors)
                factors = explicitFactors;
                return
            end

            ratio = max(imageSize) / overviewMaximumDimension;
            if ratio <= 1
                overviewFactor = 1;
            else
                overviewFactor = decimation ^ ceil( ...
                    log(ratio) / log(decimation));
            end
            if useIntermediateLevels
                factors = overviewFactor;
                while factors(end) > 1
                    factors(end + 1) = factors(end) / decimation; %#ok<AGROW>
                end
            else
                factors = unique([overviewFactor, 1], "stable");
            end
        end

        function downsampled = downsampleImage(image, factor)
            if factor == 1
                downsampled = image;
                return
            end

            smoothingSigma = max(0.8, factor / 2);
            smoothingRadius = ceil(3 * smoothingSigma);
            coordinates = single(-smoothingRadius:smoothingRadius);
            kernel = exp(-(coordinates .^ 2) ...
                ./ single(2 * smoothingSigma ^ 2));
            kernel = kernel ./ sum(kernel);
            smoothed = conv2(kernel(:), kernel(:).', ...
                single(image), "same");
            downsampled = uint8(round( ...
                smoothed(1:factor:end, 1:factor:end)));
        end

        function [predictedDx, predictedDy] = interpolatePrediction( ...
                previousResult, previousFactor, currentFactor, ...
                sampleRows, sampleColumns)
            scale = previousFactor / currentFactor;
            previousDx = double(previousResult.DisplacementX) * scale;
            previousDy = double(previousResult.DisplacementY) * scale;
            previousDx(~previousResult.Valid) = NaN;
            previousDy(~previousResult.Valid) = NaN;
            previousDx = Spin2Matcher.fillInvalidPrediction(previousDx);
            previousDy = Spin2Matcher.fillInvalidPrediction(previousDy);

            [queryX, queryY] = meshgrid(sampleColumns, sampleRows);
            queryPreviousX = 1 + (queryX - 1) / scale;
            queryPreviousY = 1 + (queryY - 1) / scale;
            fallbackDx = median(previousDx, "all", "omitnan");
            fallbackDy = median(previousDy, "all", "omitnan");
            predictedDx = interp2( ...
                previousResult.ReferenceX, previousResult.ReferenceY, ...
                previousDx, queryPreviousX, queryPreviousY, ...
                "linear", fallbackDx);
            predictedDy = interp2( ...
                previousResult.ReferenceX, previousResult.ReferenceY, ...
                previousDy, queryPreviousX, queryPreviousY, ...
                "linear", fallbackDy);
        end

        function values = fillInvalidPrediction(values)
            finiteValues = values(isfinite(values));
            if isempty(finiteValues)
                values(:) = 0;
            else
                values(~isfinite(values)) = median(finiteValues);
            end
        end

        function offsetsByTile = tileLocalOffsets( ...
                tiles, predictedDx, predictedDy, residualRadius, imageSize)
            offsetsByTile = cell(numel(tiles), 1);
            for tileIndex = 1:numel(tiles)
                tile = tiles{tileIndex};
                tilePredictedDx = predictedDx( ...
                    tile.RowIndices, tile.ColumnIndices);
                tilePredictedDy = predictedDy( ...
                    tile.RowIndices, tile.ColumnIndices);
                medianDx = median(tilePredictedDx, "all");
                medianDy = median(tilePredictedDy, "all");
                predictionMinimumDx = max( ...
                    floor(min(tilePredictedDx, [], "all")), ...
                    floor(medianDx - residualRadius(1)));
                predictionMaximumDx = min( ...
                    ceil(max(tilePredictedDx, [], "all")), ...
                    ceil(medianDx + residualRadius(1)));
                predictionMinimumDy = max( ...
                    floor(min(tilePredictedDy, [], "all")), ...
                    floor(medianDy - residualRadius(2)));
                predictionMaximumDy = min( ...
                    ceil(max(tilePredictedDy, [], "all")), ...
                    ceil(medianDy + residualRadius(2)));
                minimumDx = max(-(imageSize(2) - 1), ...
                    predictionMinimumDx ...
                    - residualRadius(1));
                maximumDx = min(imageSize(2) - 1, ...
                    predictionMaximumDx ...
                    + residualRadius(1));
                minimumDy = max(-(imageSize(1) - 1), ...
                    predictionMinimumDy ...
                    - residualRadius(2));
                maximumDy = min(imageSize(1) - 1, ...
                    predictionMaximumDy ...
                    + residualRadius(2));
                [dx, dy] = meshgrid(minimumDx:maximumDx, ...
                    minimumDy:maximumDy);
                offsetsByTile{tileIndex} = [dx(:), dy(:)];
            end
        end

        function pool = ensureThreadPool
            pool = gcp("nocreate");
            if isempty(pool)
                pool = parpool("threads");
            elseif ~isa(pool, "parallel.ThreadPool")
                error("Spin2Matcher:ThreadPoolRequired", ...
                    ["Spin2Matcher requires parpool('threads'). " ...
                    "Close the existing process pool explicitly first."]);
            end
        end

        function numberOfWorkers = resolveWorkerCount(pool, requested)
            if requested == 0
                numberOfWorkers = pool.NumWorkers;
            else
                numberOfWorkers = requested;
            end
            if numberOfWorkers > pool.NumWorkers
                error("Spin2Matcher:TooManyWorkers", ...
                    "NumWorkers cannot exceed the thread pool size of %d.", ...
                    pool.NumWorkers);
            end
        end

        function equivalent = resultsEquivalent(first, second)
            equivalent = isequaln(first.DisplacementX, second.DisplacementX) ...
                && isequaln(first.DisplacementY, second.DisplacementY) ...
                && isequal(first.Valid, second.Valid);
        end
    end
end

function mustHaveSameSize(value, referenceValue)
if ~isequal(size(value), size(referenceValue))
    error("Spin2Matcher:ImageSizeMismatch", ...
        "Reference and source images must have the same size.");
end
end

function mustBePyramidFactors(value)
if isempty(value)
    return
end
if any(~isfinite(value)) || any(value < 1) ...
        || any(value ~= fix(value)) || value(end) ~= 1 ...
        || any(diff(value) >= 0)
    error("Spin2Matcher:InvalidPyramidFactors", ...
        "PyramidFactors must be strictly descending positive integers ending in 1.");
end
end
